extern int device_id_inuse;

void 
kernel_gpu_opencl_wrapper(fp* image,
                            int Nr,
                            int Nc,
                            long Ne,
                            int niter,
                            fp lambda,
                            long NeROI,
                            int* iN,
                            int* iS,
                            int* jE,
                            int* jW,
                            int iter,
                            int mem_size_i,
                            int mem_size_j)
