    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    int blocks_x;

    int mem_size;
    mem_size = sizeof(fp) * Ne;

    fp* d_I;
    error = cudaMalloc(&d_I, mem_size);
    if (error != cudaSuccess) 
        fatal("cudaMalloc failed", __LINE__);

