    error = cudaMalloc(&d_dW, mem_size);
    if (error != cudaSuccess) 
        fatal("cudaMalloc failed", __LINE__);

    fp* d_dE;
    error = cudaMalloc(&d_dE, mem_size);
    if (error != cudaSuccess) 
        fatal("cudaMalloc failed", __LINE__);

